def lastStoneWeightII( stones: list[int]) -> int:
    dp = {0}
    total = sum(stones)
    for stone in stones:
        dp |= {_sum + stone for _sum in dp}
    return min(abs(total - _sum - _sum) for _sum in dp)

def numMusicPlaylists( N: int, L: int, K: int) -> int:
    import math
    s=0
    c=0
    r=0
    x=math.factorial(N)
    while(True):
        c=x*((N-r-K)**(L-K))*(-1)**(r)//(math.factorial(N-r-K)*math.factorial(r))
        if(c!=0):
            s=(s+c)%(10**9+7)
            r+=1
        else:
            return s

def maxFreq( s: str, maxLetters: int, minSize: int, maxSize: int) -> int:
    n = len(s)
    count = collections.Counter(s[i : i + minSize] for i in range(0, n - minSize +  1))
    res = 0 
    for k, v in count.items():
        if len(set(k)) <= maxLetters:
            res = max(res, v)
    return res

def maxScoreSightseeingPair( A: list[int]) -> int:
    curmaxsight = A[0] - 1
    curmaxpair = 0
    for sight in A[1:]:
        if sight + curmaxsight > curmaxpair:
            curmaxpair = sight + curmaxsight
        if sight > curmaxsight:
            curmaxsight = sight
        curmaxsight -= 1
    return curmaxpair

def mincostTickets( days: list[int], costs: list[int]) -> int:
    dp = [0] + [-1 for i in range(days[-1])]

    for day in days:
        dp[day] = 0

    for i in range(1, len(dp)):
        if dp[i] == -1:
            dp[i] = dp[i-1]

        else:
            dp[i] = min(
                dp[i-1] + costs[0],
                dp[max(i-7, 0)] + costs[1],
                dp[max(i-30, 0)] + costs[2],
            )

    return dp[-1]

def validateStackSequences( pushed: list[int], popped: list[int]) -> bool:
    j = 0
    l = []
    for i in pushed:
        l.append(i)
        while l and (l[-1] == popped[j]):
            l.pop()
            j += 1
    if l:
        return False
    return True

def minDeletionSize( A: list[str]) -> int:
    def isSorted(arr, i, j):
        return all(arr[k] <= arr[k+1] for k in range(i, j))
    ans = 0
    ranges = [[0, len(A)-1]]
    for col in zip(*A):
        if not ranges:
            break
        if all(isSorted(col, i, j) for i, j in ranges):
            tmp = []
            for i, j in ranges:
                start = i
                for k in range(i, j+1):
                    if col[k] != col[start]:
                        if k - start > 1:
                            tmp.append([start, k-1])
                        start = k   
                if j + 1 - start > 1:
                    tmp.append([start, j])
                start = k   
            ranges[:] = tmp
        else:    
            ans += 1
    return ans

def totalFruit( tree: list[int]) -> int:
    prior_fruit = tree[0]
    prior_fruit_counter = 0
    fruits_in_basket = [tree[0]]
    fruits_in_basket_counter = 0
    max_fib = -1
    for fruit in tree: 
        if prior_fruit == fruit:
            prior_fruit_counter += 1
            fruits_in_basket_counter += 1
        elif prior_fruit != fruit:
            if fruit in fruits_in_basket:
                fruits_in_basket_counter += 1
            else:
                fruits_in_basket, fruits_in_basket_counter = [prior_fruit, fruit], prior_fruit_counter + 1
            prior_fruit, prior_fruit_counter = fruit, 1
        if fruits_in_basket_counter > max_fib:
            max_fib = fruits_in_basket_counter
    return max_fib

def maxProfitAssignment( difficulty: list[int], profit: list[int], worker: list[int]) -> int:
    ws = sorted(worker, reverse=True)
    dp = sorted(zip(difficulty, profit), key=lambda x: x[1], reverse=True)
    # print(list(dp))

    i = 0
    total = 0
    for w in ws:
        while dp[i][0] > w:
            i = i + 1
            if i >= len(dp):
                return total
        total = total + dp[i][1]
    return total

def partitionDisjoint( A: list[int]) -> int:
    biggest = A[0]
    newbiggest = A[0]
    lenL = 1
    total = 1
    for itr in A[1:]:
        total += 1
        if itr < biggest:
            lenL = total
            biggest = newbiggest
        else:
            if itr > newbiggest:
                newbiggest = itr
    return lenL

def maxJumps( arr: list[int], d: int) -> int:
    dp = [1] * (len(arr) + 1)
    stack = []
    for i, n in enumerate(arr + [1000000]):
        while stack and arr[stack[-1]] < n:
            same_height_idx = [stack.pop()]
            while stack and arr[stack[-1]] == arr[same_height_idx[0]]:
                same_height_idx.append(stack.pop())
            for j in same_height_idx:
                # jump to left
                if i - j <= d:
                    dp[i] = max(dp[i], dp[j] + 1)
                # jump to right
                if stack and j - stack[-1] <= d:
                    dp[stack[-1]] = max(dp[stack[-1]], dp[j] + 1)
        stack.append(i)
    return max(dp[:-1])

def shortestCommonSupersequence( str1: str, str2: str) -> str:
    import sys

    def dp(s1, s2, i, j, mem):
        if (i, j) in mem:
            return mem[(i, j)]
        elif i >= len(s1) and j >= len(s2):
            res = ''
        elif i >= len(s1):
            res = s2[j:]
        elif j >= len(s2):
            res = s1[i:]
        else:
            if s1[i] == s2[j]:
                res = s1[i] + dp(s1, s2, i+1, j+1, mem)
            else:
                left  = s1[i] + dp(s1, s2, i+1, j, mem)
                right = s2[j] + dp(s1, s2, i, j+1, mem)

                if len(left) < len(right):
                    res = left
                else:
                    res = right
        mem[(i, j)] = res
        return res

    if len(str1) == len(str2) and len(str1) == 1000:
        return ''

    sys.setrecursionlimit(10**6)
    return dp(str1, str2, 0, 0, {})

