def constrainedSubsetSum( nums: list[int], k: int) -> int:
    from collections import deque
    N, queue = len(nums), deque()
    dp = [val for val in nums]
    for i, val in enumerate(nums):
        if queue and (i - queue[0] > k):
            queue.popleft()
        if queue and dp[queue[0]] > 0:
            dp[i] += dp[queue[0]]
        while queue and dp[i] >= dp[queue[-1]]:
            queue.pop()
        queue.append(i)
    return max(dp)

def superEggDrop( K: int, N: int) -> int:
    def f(t):
        a=0
        r=1
        for i in range(1, K+1):
            r *= (t-i+1)
            r//=i
            a+=r
            if a>=N: 
                break
        return a

    l, h= 1, N
    while l<h:
        m=(l+h)//2
        if f(m)<N:
            l=m+1
        else:
            h=m
    return l

def canConstruct( s: str, k: int) -> bool:
    from collections import Counter
    if k > len(s): #return False
        return False
    counter = Counter(s)
    odd_counts = 0

    for char in counter:
        if counter[char] % 2 == 1:
            odd_counts += 1

    return odd_counts <= k

def findLengthOfShortestSubarray( arr: list[int]) -> int:
    n = len(arr)
    if n<=1: 
        return 0
    l,r = n,-1

    for i in range(1,n):
        if arr[i]<arr[i-1]:
            l = i
            break
    # monotonicially increasing
    if l == n: return 0

    for j in range(n-2,-1,-1):
        if arr[j]>arr[j+1]:
            r = j
            break

    # you can delete all to the left of r (including r)
    # you can also delete all to the right of l (including l)
    ans = min(r+1,n-l)

    i = 0
    # sliding window, find the rightmost i for each j
    # note at all time i must be less than l
    for j in range(r+1,n):
        while i<l and arr[i] <= arr[j]:
            i += 1
        ans = min(ans,j-i)
    return ans

def maxDiff( num: int) -> int:
