def canArrange( arr: list[int], k: int) -> bool:
    freq = [0] * k

    for n in arr:
        freq[n%k] += 1

    if freq[0] % 2: return False

    for i in range(1, (k//2)+1):
        if freq[i] != freq[k-i]: return False

    if k%2 is 0:
        if freq[k//2]%2: return False

    return True

def getLengthOfOptimalCompression( s: str, k: int) -> int:
    n = len(s)

    def compLen(c):
        return 1 + len(str(c)) if c > 1 else 1

    @lru_cache(None)
    def dp(i, k): # return {head: (len, -head_count)}
        if (n - i) <= k:
            return {} # remove all
        x, res = s[i], {}
        # remove
        if k:
            res = dp(i + 1, k - 1)
        # keep
        keep = dp(i + 1, k)
        t = [(1 + min((leng for leng, _ in list(keep.values())), default=0), -1)]
        if x in keep:
            leng, negc = keep[x]
            leng, negc = (leng - compLen(-negc) + compLen(-negc + 1),
                          negc - 1)
            t.append((leng, negc))
        if x in res:
            t.append(res[x])
        res[x] = min(t)
        return res

    m = dp(0, k)
    return min((leng for leng, _ in list(m.values())), default = 0)

