def hasAllCodes( s: str, k: int) -> bool:
    if len(s) < 2 ** k + k - 1:
        return False # Cannot be a string, as this is the de brujin length
    target = 2 ** k
    seen = set()
    cur_len = 0
    for end in range(k, len(s) + 1):
        chunk = s[end - k: end]
        if chunk not in seen:
            cur_len += 1
            seen.add(chunk)
            if cur_len == target:
                return True
    return False

def largestNumber( cost: list[int], target: int) -> str:
    dp = [0] + [-target]*target
    for t in range(1, target+1):
        dp[t] = max([dp[t-i] for i in cost if i<=t]+[dp[t]]) + 1
    if dp[-1]<=0: return '0'
    res = ''
    for i in range(8, -1, -1):
        while target>=cost[i] and dp[target-cost[i]]==dp[target]-1:
            res += str(i+1)
            target -= cost[i]
    return res

def minOperationsMaxProfit( customers: list[int], boardingCost: int, runningCost: int) -> int:
    if runningCost >= 4 * boardingCost:
        return -1
    result = sum(customers) // 4
    if (sum(customers) % 4) * boardingCost > runningCost:
        result += 1
    for customer in customers:
        if customer <= 1:
            result += 1
        else:
            break
    return result

def atMostNGivenDigitSet( digits: list[str], n: int) -> int:

    count = 0
    length = 1
    n_str = str(n)
    while length < len(n_str):
        count+= len(digits)**length
        length+=1

    digits_sorted = sorted(digits)


    ## now length should equal to len(n), we compare the number with same length
    current_digit = 0
    while current_digit < length:
        for digit in digits_sorted:
            next_round = False
            if digit < n_str[current_digit]:
                count+=len(digits)**(length-current_digit-1)
            elif digit > n_str[current_digit]:
                return count
            else:
                if current_digit == length-1:
                    return count+1
                else: 
                    current_digit+=1
                    next_round = True
                    break
        if not next_round:
            return count

    return count

def countTriplets( A: list[int]) -> int:
    counters = [0] * (1 << 16)
    counters[0] = len(A)
    for num in A:
        mask = (~num) & ((1 << 16) - 1)
        sm = mask
        while sm != 0:
            counters[sm] += 1
            sm = (sm - 1) & mask

    return sum(counters[num1 & num2] for num1 in A for num2 in A)

def maxSubarraySumCircular( A: list[int]) -> int:
    N = len(A)
    if(N==0):
        return 0
    curr_max = A[0]
    global_max = A[0]
    curr_min = A[0]
    global_min = A[0]
    flag = 0 
    if(A[0]>=0):
        flag=1

    for i in range(1, N):
        if(A[i]>=0):
            flag=1
        if(curr_max >= 0):
            curr_max = curr_max + A[i]    
        else:
            curr_max = A[i]

        if(curr_min >= 0):
            curr_min = A[i]
        else:
            curr_min = curr_min + A[i] 

        if(curr_max > global_max):
            global_max = curr_max
        if(curr_min < global_min):
            global_min = curr_min
    if(flag==0):
        return max(A)
    return max(global_max, sum(A) - global_min)

