def mergeStones( stones: list[int], K: int) -> int:
    n = len(stones)
    if (n - 1) % (K - 1) != 0:
        return -1
    prefix = [0]
    for s in stones:
        prefix.append(prefix[-1] + s)
    @lru_cache(None)
    def dp(i, j):
        if j - i + 1 < K:
            return 0
        res = 0
        if (j - i) % (K - 1) == 0:
            res = prefix[j+1] - prefix[i]
        return res + min(dp(i, mid) + dp(mid+1, j) for mid in range(i, j, K - 1))
    return dp(0, n - 1)

def numFactoredBinaryTrees( A: list[int]) -> int:

    mod = 10**9 + 7

    nums_set = set(A)
    nums = A.copy()
    nums.sort()
    counts = {}
    total = 0

    for n in nums:
        n_count = 1
        for d in nums:
            if d * d > n:
                break
            if n % d != 0:
                continue
            e = n // d
            if e not in nums_set:
                continue

            subtrees = (counts[d] * counts[e]) % mod
            if d != e:
                subtrees = (subtrees * 2) % mod
            n_count = (n_count + subtrees) % mod
        counts[n] = n_count % mod
        total = (total + n_count) % mod

    return total

def movesToMakeZigzag( nums: list[int]) -> int:
    n = len(nums)
    res0 = 0
    for i in range(0, n, 2):
        nei = min(nums[j] for j in [i - 1, i + 1] if 0 <= j <= n-1)
        if nums[i] >= nei:
            res0 += nums[i] - nei + 1
    res1 = 0
    for i in range(1, n, 2):
        nei = min(nums[j] for j in [i - 1, i + 1] if 0 <= j <= n-1)
        if nums[i] >= nei:
            res1 += nums[i] - nei + 1
    return min(res0, res1)

