def minNumberOfFrogs( croakOfFrogs: str) -> int:
    # valid string? can be seperated into full croaks:
    ### dict of letters. c, r, o, a, k should all be equal, nothing else in
    if len(croakOfFrogs)%5!=0 or croakOfFrogs[0]!='c' or croakOfFrogs[-1]!='k':
        return -1

    letters = {
        'c': 0,
        'r': 0,
        'o': 0,
        'a': 0,
        'k': 0
    }

    frogs = 0
    temp = 0

    for l in croakOfFrogs:
        letters[l] += 1
        temp = letters['c'] - letters['k']
        if temp > frogs:
            frogs = temp


    c_count = letters['c']
    for letter in letters:
        if letters[letter] != c_count:
            return -1

    return frogs

def subarrayBitwiseORs( A: list[int]) -> int:
    res = set()
    cur = set()
    for a in A:
        cur = {a | i for i in cur}
        cur |= {a}
        res |= cur
    return len(res)

def orderlyQueue( S: str, K: int) -> str:
    if K >= 2:
        return ''.join(sorted(S))

    length = len(S)
    S = S + S
    i, j, k = 0, 1, 0
    while j + k < len(S) and k < length:
        if S[i + k] == S[j + k]:
            k += 1
            continue
        elif S[i + k] < S[j + k]:
            j = j + k + 1
        else:
            i = max(i + k + 1, j)
            j = i + 1
        k = 0
    return S[i : i + length]

def longestWPI( hours: list[int]) -> int:
    ans, count, seen = 0, 0, {}
    for i, hour in enumerate(hours):
        count = count + 1 if hour > 8 else count - 1
        if count > 0:
            ans = i + 1
        else:
            if count not in seen:
                seen[count] = i
            if count - 1 in seen:
                ans = max(ans, i - seen[count - 1])
    return ans

