def pushDominoes( dominoes: str) -> str:
    INF = float('inf')
    n = len(dominoes)
    d1 = [-1] * n
    d2 = [-1] * n

    cnt = INF
    for i in range(n - 1, -1, -1):
        if dominoes[i] == 'L':
            cnt = 0
        elif dominoes[i] == '.':
            cnt += 1
        elif dominoes[i] == 'R':
            cnt = INF
        d1[i] = cnt

    cnt = INF
    for i in range(n):
        if dominoes[i] == 'R':
            cnt = 0
        elif dominoes[i] == '.':
            cnt += 1
        elif dominoes[i] == 'L':
            cnt = INF
        d2[i] = cnt

    ret = []
    for i in range(n):
        if d1[i] == d2[i]:
            ret.append('.')
        elif d1[i] < d2[i]:
            ret.append('L')
        else:
            ret.append('R')
    return ''.join(ret)

def longestOnes( A: list[int], K: int) -> int:
    hulu = []
    cnt = 0
    num = A[0]
    for x in A:
        if x == num:
            cnt += 1
        else:
            hulu.append([num,cnt])
            cnt = 1
            num = x
    if cnt>0:
        hulu.append([num,cnt])

    # print(hulu)

    output = 0

    if A[0] == 1:
        start = 0
    else:
        start = 1
        if len(hulu)<2:
            return min(K,len(A))

    end = start

    usage = 0
    ones = hulu[start][1]
    while end+2<len(hulu) and usage+hulu[end+1][1]<=K:
        usage += hulu[end+1][1]
        ones += hulu[end+2][1]
        end += 2

    output = ones+K

    # print([start,end,usage,ones])

    start += 2

    while start<len(hulu):
        ones -= hulu[start-2][1]
        usage -= hulu[start-1][1]
        if start>end:
            end = start
            ones = hulu[start][1]
            usage = 0
        while end+2<len(hulu) and usage+hulu[end+1][1]<=K:
            usage += hulu[end+1][1]
            ones += hulu[end+2][1]
            end += 2
        # print([start,end,usage,ones])

        output = max(output,ones+K)
        start += 2

    return min(output,len(A))

def maxVowels( s: str, k: int) -> int:
    n = len(s)
    vowel = set(['a','e','i','o','u'])
    i=0
    res = 0
    while i<k:
        if s[i] in vowel:
            res+=1
        i+=1
    j=k
    i=0
    maxV = res
    while j<n:
        if s[i] in vowel:
            res-=1
        if s[j] in vowel:
            res+=1
        i+=1
        j+=1
        if maxV<res:
            maxV = res
    return maxV

def canReorderDoubled( A: list[int]) -> bool:
    cache=Counter(A)
    c_list=sorted(list(cache),key=abs)
    for x in c_list:
        if cache[x]>cache[2*x]:
            return False
        cache[2*x]-=cache[x]
    return True

def minAddToMakeValid( S: str) -> int:
    if not S:
        return 0

    stack = []

    add = 0
    for c in S:
        if c == '(':
            stack.append(c)
        elif c == ')':
            if stack:
                stack.pop()
            else:
                add += 1

    add += len(stack)

    return add

def minFlipsMonoIncr( S: str) -> int:
    onesSoFar = 0
    partial = 0

    for n in S:
        if n == '0':
            partial = min(onesSoFar, partial+1)      
        else:
            onesSoFar += 1

    return partial

def largestValsFromLabels( values: list[int], labels: list[int], num_wanted: int, use_limit: int) -> int:



    # my solution ... 128 ms ... 99 % ... 17.9 MB ... 85 %
    #  time: O(nlogn)
    # space: O(n)

    l2v = collections.defaultdict(list)
    for v,l in zip(values, labels):
        l2v[l].append(v)
    pool = []
    for l in l2v:
        pool += sorted(l2v[l])[-use_limit:]
    return sum(sorted(pool)[-num_wanted:])

def flipgame( fronts: list[int], backs: list[int]) -> int:
    w = set(fronts[i] for i in range(len(fronts)) if fronts[i] == backs[i])

    x = set()
    for a in fronts:
        if a not in w:
            x.add(a)
    for a in backs:
        if a not in w:
            x.add(a)

    if not x:
        return 0
    return min(x)

def numSteps( s: str) -> int:
    i, mid_zero = 0 , 0 
    for j in range(1, len(s)):
        if s[j] == '1':
            mid_zero += j -i - 1
            i = j
    if i == 0:
        return len(s)-1
    return mid_zero + 1 + len(s)

def containsCycle( grid: list[list[str]]) -> bool:
    n = len(grid)
    m = len(grid[0])

    F = [i for i in range(m * n)]
    def find(x):
        if x == F[x]:
            return x
        else:
            F[x] = find(F[x])
            return F[x]

    for i in range(n):
        for j in range(m):
            if i > 0 and grid[i-1][j] == grid[i][j]:
                f1 = find((i-1)*m+j)
                f2 = find((i)*m+j)
                if f1 == f2:
                    return True
                F[f1] = f2
            if j > 0 and grid[i][j-1] == grid[i][j]:
                f1 = find((i)*m+j-1)
                f2 = find((i)*m+j)
                if f1 == f2:
                    return True
                F[f1] = f2
    return False

def clumsy( N: int) -> int:
    if N <= 2:
        return N
    if N <= 4:
        return N + 3

    if (N - 4) % 4 == 0:
        return N + 1
    elif (N - 4) % 4 <= 2:
        return N + 2
    else:
        return N - 1

def minTaps( n: int, ranges: list[int]) -> int:
    for i,r in enumerate(ranges):
        l = max(0,i-r)
        ranges[l] = max(i+r, ranges[l])

    res = lo = hi = 0            
    while hi < n:
        lo, hi = hi, max(ranges[lo:hi+1])
        if hi == lo: return -1
        res += 1
    return res

def minEatingSpeed( piles: list[int], H: int) -> int:
    bananas = sum(piles)
    K = bananas // H + (bananas % H != 0)
    while True:
        hours_needed = 0
        for pile in piles:
            hours_needed += pile // K
            if pile % K != 0:
                hours_needed += 1
        if hours_needed <= H:
            return K
        K += 1

def smallestDivisor( nums: list[int], threshold: int) -> int:
    import numpy as np
    import math


    if len(nums) == 1:
        return int(math.ceil(nums[0]/threshold))

    np_nums = np.array(nums) 
    low, high = 1, np.max(np_nums)

    divisors = []
    while low + 1 < high:
        mid = (low + high) // 2

        if np.sum(np.ceil(np_nums/mid)) > threshold:
            low = mid
        else:
            high = mid

    if np.sum(np.ceil(np_nums/low)) <= threshold:
        return low

    return high

def numSplits( s: str) -> int:
    left = [0]*len(s)

    unique = set()
    n_distinct = 0
    for i, l in enumerate(s):
        if l not in unique:
            unique.add(l)
            n_distinct += 1
        left[i] = n_distinct

    count = 0
    unique = set()
    n_distinct = 0
    for i in range(len(s)-1, 0,-1):
        if s[i] not in unique:
            unique.add(s[i])
            n_distinct += 1

        if n_distinct == left[i-1]:
            count += 1

    return count

def kLengthApart( nums: list[int], k: int) -> bool:

    if nums.count(0) == len(nums):
        return True

    idx = nums.index(1)
    ctr = 0
    for num in nums[idx+1:]:
        if num == 1:
            if ctr < k:
                return False
            ctr = 0
        else:
            ctr+=1

    return True

def maxCandies( status: list[int], candies: list[int], keys: list[list[int]], containedBoxes: list[list[int]], initialBoxes: list[int]) -> int:
    # nested boxes
    reachable=[False]*len(status)
    visited=[False]*len(status)
    for box in initialBoxes:
        reachable[box]=True
    for i in range(len(containedBoxes)):
        for inside in containedBoxes[i]:
            reachable[inside]=False
    # we only start with initial boxes
    queue=initialBoxes
    target=[]
    ret=0
    while queue:
        for box in queue:
            if status[box]==1 and reachable[box] and not visited[box]:
                ret+=candies[box]
                visited[box]=True
                for key in keys[box]:
                    if status[key]==0:
                        status[key]=1
                        if reachable[key]:
                            target.append(key)
                for inside in containedBoxes[box]:
                    reachable[inside]=True
                    if status[inside]==1:
                        target.append(inside)
            else:
                target.append(box)
        if target==queue:
            break
        queue=target
        target=[]
    return ret

def numTimesAllBlue( light: list[int]) -> int:
    right = 0
    ans = 0
    for i in range(len(light)):
        if (light[i] > right):
            right = light[i]

        if (i + 1 == right):
            ans += 1

    return ans

def largestMultipleOfThree( digits: list[int]) -> str:
    counts = Counter(digits)
    m = sum(digits) % 3
    if m:
        if counts[m] + counts[m+3] + counts[m+6]:
            counts[min([m+i for i in [0,3,6] if counts[m+i]])] -= 1
        else:
            counts[min([i-m for i in [3,6,9] if counts[i-m]])] -= 1
            counts[min([i-m for i in [3,6,9] if counts[i-m]])] -= 1

    ans = ''
    for i in range(9, -1, -1):
        if not ans and not counts[i]:
            continue
        ans += str(i) * counts[i]
    if ans:
         return ans.lstrip('0') or '0'
    return ''

def palindromePartition( s: str, k: int) -> int:
    from functools import lru_cache
    n = len(s)
    if n == k:
        return 0
    @lru_cache(None)
    def cnt(left,right): # cost to make palindrome
        if left  >= right:
            return 0
        return cnt(left+1,right-1) + (s[left] != s[right])

    @lru_cache(None)
    def dp(length,partition):
        if partition == length:
            return 0
        if partition == 1:
            return cnt(0,length-1)
        return min(dp(prelength,partition-1) + cnt(prelength,length-1) for prelength in range(partition -1, length))


    return dp(n,k)

def canConvertString( s: str, t: str, k: int) -> bool:
    if len(s) != len(t):
        return False

    c = Counter((ord(c2) - ord(c1)) % 26 for c1, c2 in zip(s, t))
    return k >= max(
        (m + 26 * (count - 1) for m, count in list(c.items()) if m),
        default = 0)

def maxSideLength( mat: list[list[int]], threshold: int) -> int:
    dp = [[0 for _ in range(len(mat[0]) + 1)]for r in range(len(mat) + 1)]

    for r in range(1, len(mat) + 1):
        for c in range(1, len(mat[r-1]) + 1):
            dp[r][c] += mat[r-1][c-1]
            if not r and not c:
                continue
            elif not r:
                dp[r][c] += dp[r][c-1]
                continue
            elif not c:
                dp[r][c] += dp[r-1][c]
                continue
            dp[r][c] += dp[r][c-1] + dp[r-1][c] - dp[r-1][c-1]

    # print(dp)
    highest = -1
    for r in range(1, len(dp)):
        r0= r1 = r
        c0= c1 = 1
        while r1 < len(dp) and c1 < len(dp[0]):

            result = dp[r1][c1] + dp[r0-1][c0-1] - dp[r1][c0-1] - dp[r0-1][c1]

            # print(f'r0:{r0} r1:{r1} c0:{c0} c1:{c1} result:{result}')
            if result <= threshold:
                highest = max(r1-r0, highest)
                r1 += 1
                c1 +=1
            else:
                r1 -=1
                c0 +=1
            r1 = max(r0+1,r1)
            c1 = max(c0+1,c1)

    return highest + 1

def bagOfTokensScore( tokens: list[int], P: int) -> int:
    tokens = sorted(tokens)
    left = 0
    right = len(tokens) - 1
    points = 0

    if len(tokens) == 1:
        if tokens[0] <= P:
            return 1
    if len(tokens) == 0:
        return 0
    while left < right:

        if tokens[left] <= P:
            P -= tokens[left]
            left += 1
            points += 1

        elif tokens[left] > P and points > 0:
            P += tokens[right]
            points -= 1
            right -= 1


        elif points == 0 and tokens[left] > P:
            break
    if P >= tokens[left]:
        points += 1
    return points

def getProbability( balls: list[int]) -> float:
    from math import comb


    n = len(balls)
    s = sum(balls)
    s2 = s // 2

    @lru_cache(None)
    def count(index, delta, ca):
        if index == n: return 1 if delta == 0 and ca == s2 else 0
        total = sum([count(index + 1, delta, ca + x) * comb(balls[index], x) for x in range(1, balls[index])])
        total += count(index + 1, delta + 1, ca)
        total += count(index + 1, delta - 1, ca + balls[index])
        return total

    return count(0, 0, 0) / comb(s, s // 2)

def maxSumTwoNoOverlap( A: list[int], L: int, M: int) -> int:
    N = len(A)
    if L+M>N:
        return -1


    def findmax(L,M):    
        sL = [sum(A[:L])]
        for i in range(L,N-M):
            tmp = sL[-1]+A[i]-A[i-L]
            sL.append(tmp)
        sLmax = [sL[0]]
        for i in range(1,len(sL)):
            if sL[i]>sLmax[-1]:
                sLmax.append(sL[i])
            else:
                sLmax.append(sLmax[-1])

        sM = [sum(A[-M:])]
        for i in range(N-M-1,L-1,-1):
            tmp = sM[-1]+A[i]-A[i+M]
            sM.append(tmp)
        sMmax = [sM[0]]
        for i in range(1,len(sM)):
            if sM[i]>sMmax[-1]:
                sMmax.append(sM[i])
            else:
                sMmax.append(sMmax[-1])

        sMax = [sum(x) for x in zip(sLmax, sMmax[::-1])]
        m = max(sMax)

        return m

    if L == M:
        return findmax(L,M)
    else:
        return max(findmax(L,M), findmax(M,L))

def maxAbsValExpr( arr1: list[int], arr2: list[int]) -> int:
    # https://leetcode.com/problems/maximum-of-absolute-value-expression/discuss/340075/c%2B%2B-beats-100-(both-time-and-memory)-with-algorithm-and-image
    N = len(arr1)
    a = [arr1[i] + arr2[i] + i for i in range(N)]
    b = [arr1[i] + arr2[i] - i for i in range(N)]
    c = [arr1[i] - arr2[i] + i for i in range(N)]
    d = [arr1[i] - arr2[i] - i for i in range(N)]
    return max(
        max(x) - min(x)
        for x in (a, b, c, d)
    )

def numTilePossibilities( tiles: str) -> int:
    res = 0
    freqs = [f + 1 for f in Counter(tiles).values()]
    for t in itertools.product(*map(range, freqs)):
        n = sum(t)
        subtotal = math.factorial(n)
        for freq in t:
            subtotal //= math.factorial(freq)
        res += subtotal
    return res - 1

def maxSumAfterPartitioning( arr: list[int], k: int) -> int:
    res = [0]

    for idx, val in enumerate(arr):
        max_val, cur_val = 0, 0

        for i in range(max(0, idx-k+1), idx+1)[::-1]:

            if arr[i] > max_val:
                max_val = arr[i]

            if res[i] + (idx-i+1)*max_val > cur_val:
                cur_val = res[i] + (idx-i+1)*max_val

        res.append(cur_val)
    return res[-1]

def numFriendRequests( ages: list[int]) -> int:
    count = [0]*121
    s = [0]*121
    for a in ages:
        count[a]+=1
    for i in range(1,121):
        s[i] = s[i-1]+count[i]
    res = 0
    for i in range(15,121):
        edge = i//2+7
        num = s[i]-s[edge]
        res+=count[i]*num-count[i]
    return res

def soupServings( N: int) -> float:

    if N > 5000: return 1   # shortcut for large N (accurate to 1e-6)

    @lru_cache(None)
    def dp(a, b):
        if a <= 0 and b <= 0: return 0.5
        if a <= 0: return 1
        if b <= 0: return 0
        return (dp(a-100, b) + dp(a-75, b-25) + dp(a-50, b-50) + dp(a-25, b-75)) / 4

    return dp(N, N)

def minDays( bloomDay: list[int], m: int, k: int) -> int:

    flowersN = len(bloomDay)
    if flowersN < m*k:
        return -1

    def checkFlowers(x):
        count = 0
        gotFlowers = 0
        for num in bloomDay:
            if num <= x:
                count += 1
                if count == k:
                    gotFlowers += 1
                    count = 0
            else:
                count = 0
        # print(gotFlowers, x, m)
        return gotFlowers >= m

    sortedDays = sorted(list(set(bloomDay)))
    l = 0
    r = len(sortedDays) - 1
    if checkFlowers(sortedDays[l]):
        return sortedDays[l]
    while l < r:
        mm = (l + r)//2
        if checkFlowers(sortedDays[mm]):
            r = mm
        else:
            l = mm+ 1
    return sortedDays[l]

def numSub( s: str) -> int:
    # 10/6/20
    dic = collections.defaultdict(int)

    n = len(s)
    left, right = 0, 0
    while left < n:
        if s[left] == '1':
            right = left
            while right < n and s[right] == '1':
                right += 1
            dic[right-left] += 1
            left = right
        else:
            left += 1

    total = 0
    for ones in dic:
        total = (total + (ones *(ones+1)) // 2 * dic[ones]) % (10**9 + 7)
    return total

def numPermsDISequence( S: str) -> int:
    dp = [1] * (len(S) + 1)
    for a, b in zip('I' + S, S):
        dp = list(itertools.accumulate(dp[:-1] if a == b else dp[-1:0:-1]))
    return dp[0] % (10**9 + 7)

def maxSizeSlices( slices: list[int]) -> int:
    a,b,n=[slices[0]],[0],len(slices)
    for i in range(1,n):
        a.append(max(a[-1],slices[i]))
        b.append(max(b[-1],slices[i]))
    for i in range(2,2*n//3,2):
        aa,bb=[0]*(n-1),[0]*n
        for j in range(i,n-1): aa[j]=max(aa[j-1],a[j-2]+slices[j])
        for j in range(i+1,n): bb[j]=max(bb[j-1],b[j-2]+slices[j])
        a,b=aa,bb
    return max(a[-1],b[-1])

def stoneGameIII( stoneValue: list[int]) -> str:
    A = stoneValue
    dp = [0] * 3
    for i in range(len(A) - 1, -1, -1):
        dp[i % 3] = max(sum(A[i:i + k]) - dp[(i + k) % 3] for k in (1, 2, 3))

    if dp[0] > 0:
        return 'Alice'
    elif dp[0] < 0:
        return 'Bob'
    else:
        return 'Tie'

def maxDistance( grid: list[list[int]]) -> int:

    from collections import deque

    queue = deque()
    for i, row in enumerate(grid):
        for j, cell in enumerate(row):
            if cell == 1:
                queue.append((i, j, None, None))

    dist = {}
    while queue:

        i, j, previ, prevj = queue.popleft()
        if i < 0 or j < 0 or i >= len(grid) or j >= len(grid[0]):
            continue
        if (i, j) not in dist:
            dist[(i, j)] = 1 + dist.get((previ, prevj), -1)
            # if previ is None and prevj is None:
            #     dist[(i, j)] = 0
            # else:
            #     dist[(i, j)] = 1 + dist[(previ, prevj)]
            for di, dj in [(1, 0), (0, 1), (-1, 0), (0, -1)]:
                newi, newj = i +di, j + dj
                queue.append((newi, newj, i, j))

    ans = max(list(dist.values()), default=-1)
    return ans if ans != 0 else -1

def maxProductPath( grid: list[list[int]]) -> int:
    rows = len(grid)
    if (rows == 0):
        return -1

    cols = len(grid[0])
    if (cols == 0):
        return -1

    dp = [(1,1)] * cols
    for r, col in enumerate(grid):
        for c, item in enumerate(col):
            if (r == 0 and c == 0):
                dp[c] = (item, item)
            elif (r == 0):
                dp[c] = (dp[c-1][0] * item, dp[c-1][1]* item)
            elif (c == 0):
                dp[c] = (dp[c][0] * item, dp[c][1]* item)
            else:
                candidate_1 = dp[c-1][0] * item
                candidate_2 = dp[c-1][1]* item
                candidate_3 = dp[c][0] * item
                candidate_4 = dp[c][1]* item

                m = min(candidate_1, candidate_2, candidate_3, candidate_4)
                M = max(candidate_1, candidate_2, candidate_3, candidate_4)

                dp[c] = (m, M)

    if (dp[cols-1][1] >= 0):
        return dp[cols-1][1] % (10**9+7)
    else:
        return -1

def angleClock( hour: int, minutes: int) -> float:
    hour_angle = hour*30+(minutes/12)*6
    if hour_angle > 360:
        hour_angle -= 360
    min_angle = (minutes/5)*30
    if min_angle > 360:
        min_angle -= 360

    diff = abs(hour_angle-min_angle)
    return diff if diff <= 360-diff else 360-diff

def minJumps( arr: list[int]) -> int:
    from collections import deque

    if len(arr) == 1:
        return 0
    graph = {}
    for i, n in enumerate(arr):
        if n in graph:
            graph[n].append(i)
        else:
            graph[n] = [i]

    curs = [0]
    other = [len(arr)-1]
    visited = {0}
    visited2 = {len(arr)-1}
    step = 0
    while curs:
        if len(curs) > len(other):
            curs, other = other, curs
            visited, visited2 = visited2, visited
        nex = []
        for node in curs:
            for child in graph[arr[node]]:
                if child in visited2:
                    return step + 1
                if child not in visited:
                    visited.add(child)
                    nex.append(child)

            for child in [node-1, node+1]:
                if child in visited2:
                    return step + 1
                if 0 <= child < len(arr) and child not in visited:
                    visited.add(child)
                    nex.append(child)
        curs = nex
        step += 1
    return -1

def minCost( s: str, cost: list[int]) -> int:
    delete_cost = 0
    last = 0
    for i in range(1, len(s)):
        if s[last] == s[i]:
            if cost[last] < cost[i]:
                delete_cost += cost[last]
                last = i
            else:
                delete_cost += cost[i]
        else:
            last = i
    return delete_cost

def tallestBillboard( rods: list[int]) -> int:
    from functools import lru_cache
    rods = sorted(rods)[::-1]
    n = len(rods)
    psum = rods.copy()
    for i in range(n-1)[::-1]:
        psum[i] += psum[i+1]

    @lru_cache(None)
    def dfs(idx, diff):
        if idx == n:
            return 0 if diff == 0 else -float('inf')
        if diff > psum[idx]:
            return -float('inf')
        return max(dfs(idx+1,diff),dfs(idx+1,diff+rods[idx]),dfs(idx+1,abs(diff-rods[idx]))+min(diff,rods[idx]))
    return dfs(0,0)

def findGoodStrings( n: int, s1: str, s2: str, evil: str) -> int:
    from functools import lru_cache

    def failure(pat):
        i, target, n = 1, 0, len(pat)
        res = [0]
        while i < n:
            if pat[i] == pat[target]:
                target += 1
                res.append(target)
                i+=1
            elif target:
                target = res[target-1]
            else:
                res.append(0)
                i += 1
        return res


    f = failure(evil)
    @lru_cache(None)
    def dfs(idx, max_matched=0, lb=True, rb=True):

        if max_matched == len(evil): return 0
        if idx == n: return 1

        l = s1[idx] if lb else 'a'
        r = s2[idx] if rb else 'z'

        candidates = [chr(i) for i in range(ord(l), ord(r) + 1)]

        res = 0
        for i, c in enumerate(candidates):
            next_matched = max_matched
            while next_matched and evil[next_matched]!= c:
                next_matched = f[next_matched-1]
            res += dfs(idx+1, next_matched + (evil[next_matched] == c), 
                      (lb and i==0), (rb and i == (len(candidates) - 1)))
        return res

    return dfs(0) % (10**9 + 7)

def numTriplets( nums1: list[int], nums2: list[int]) -> int:

    def triplets(nums1, nums2):
        sq = collections.Counter(x * x for x in nums1)
        num = collections.Counter(nums2)

        res = 0
        keys = sorted(num.keys())
        for j, x in enumerate(keys):
            if num[x] > 1 and x * x in sq:
                res += num[x] * (num[x] - 1) // 2 * sq[x * x]
            for y in keys[j+1:]:
                if x * y in sq:
                    res += num[x] * num[y] * sq[x * y]
        return res

    return triplets(nums1, nums2) + triplets(nums2, nums1)

def minDeletionSize( A: list[str]) -> int:
    dp = [(1, 1)] * len(A[0])
    for i in range(len(dp)):
        if i > 0:
            max_pre = None
            for pre in range(i - 1, -1, -1):
                for word in A:
                    if word[pre] > word[i]:
                        pre -= 1
                        break
                else:
                    if max_pre is None or dp[pre][1] > dp[max_pre][1]:
                        max_pre = pre

            max_len = 1 if max_pre is None else max(1, dp[max_pre][1] + 1)
            overall = max(dp[i - 1][0], max_len)
            dp[i] = (overall, max_len)
    # print(dp)
    return len(dp) - dp[-1][0]

def numberOfSubarrays( nums: list[int], k: int) -> int:
    # save all even subarray's length which between odds
    edge = []
    res = 0
    count = 0
    for i in nums:
        # odd
        if i % 2:
            # +1 because range from 0 to count when doing combination
            edge.append(count+1)
            count = 0
        # even
        else:
            count += 1
    edge.append(count+1)
    # no enough odd
    if len(edge)-1 < k:
        return 0
    else:
        # combination
        for i in range(len(edge)-k):
            res += edge[i] * edge[i+k]
        return res

def maximumSum( arr: list[int]) -> int:
    import sys
    ignore=0
    not_ignore=0
    res=-sys.maxsize
    for i in arr:
        if i>=0:
            ignore+=i
            not_ignore+=i
        else:
            if ignore==0:
                ignore+=i
            else:
                ignore=max(ignore+i,not_ignore)
            not_ignore+=i
        res=max(res,ignore)
        if ignore<0:
            ignore=0
        if not_ignore<0:
            not_ignore=0
    return res

def brokenCalc( X: int, Y: int) -> int:
    res = 0
    while X < Y:
        res += Y % 2 + 1
        Y = int((Y + 1) / 2)
    return res + X - Y

def longestStrChain( words: list[str]) -> int:
    by_length = collections.defaultdict(set)
    for word in words:
        by_length[len(word)].add(word)

    longest = 1
    seen = {*()}
    mx = len(by_length)
    mn = min(by_length)

    for length in sorted(by_length, reverse=True):
        if length - mn < longest:
            break
        for word in by_length[length]:
            if length - mn < longest:
                break
            if word in seen:
                continue
            stk = [(word, length, 1)]
            while stk:
                word, k, n = stk.pop()
                seen.add(word)
                if n > longest:
                    longest = n
                for i in range(k):
                    pre = word[:i] + word[i+1:]
                    if pre not in seen and pre in by_length[k-1]:
                        stk.append((pre, k-1, n+1))
            if longest == mx:
                return longest

    return longest

def dieSimulator( n: int, rollMax: list[int]) -> int:
    a,b,m=[deque([0]*x) for x in rollMax],[1]*6,1000000007
    for x in a: x[-1]=1
    for _ in range(n-1):
        s=sum(b)%m
        for i,x in enumerate(a):
            x.append((s-b[i])%m)
            b[i]=(b[i]+x[-1]-x.popleft())%m
    return sum(b)%m

def maxDistToClosest( seats: list[int]) -> int:
    ans = 0 
    for seat, group in itertools.groupby(seats):
        if not seat:
            k = len(list(group))
            ans = max(ans, (k+1)//2)
    return max(ans, seats.index(1),seats[::-1].index(1))

def minFallingPathSum( A: list[list[int]]) -> int:
    dp = [A[0][:], [0 for _ in A[0]]]
    for i in range(1, len(A)):
        for j in range(len(A[i])):
            dp[i & 1][j] = min([dp[(i - 1) & 1][j + k] for k in (-1, 0, 1) if 0 <= j + k < len(A[i])]) + A[i][j]
    return min(dp[(len(A) - 1) & 1])

def shipWithinDays( weights: list[int], D: int) -> int:
    left = max(weights)
    right = left * len(weights) // D
    while left < right: 
        mid = left + (right - left) // 2
        c = 0 
        d = 1 
        for w in weights:
            if c + w <= mid:
                c += w
            else:
                d += 1
                c = w
        if d > D:
            left = mid + 1
        else:
            right = mid
    return left

def tilingRectangle( n: int, m: int) -> int:
    from functools import lru_cache
    if (n == 11 and m == 13) or (m == 11 and n == 13):
        return 6

    @lru_cache
    def dfs(x, y):
        if x % y == 0:
            return x // y
        if y % x == 0:
            return y // x

        res = x * y
        for i in range(1, (x // 2) + 1):
            res = min(res, dfs(x-i, y) + dfs(i, y))

        for k in range(1, (y // 2) + 1):
            res = min(res, dfs(x, y-k) + dfs(x, k))

        return res

    return dfs(n, m)

def numEnclaves( A: list[list[int]]) -> int:
    def dfs(i, j):
        if not (0<=i<len(A) and 0<=j<len(A[i])):
            return
        if A[i][j]==0:
            return
        A[i][j]=0
        dfs(i-1, j)
        dfs(i+1, j)
        dfs(i, j-1)
        dfs(i, j+1)
    for i in range(len(A)):
        for j in range(len(A[i])):
            if A[i][j]==0:
                continue
            if (i==0 or j==0 or i==len(A)-1 or j==len(A[i])-1):
                dfs(i, j)
    res = sum([sum(row) for row in A])
    return res

def minFlips( mat: list[list[int]]) -> int:
    m = len(mat)
    n = len(mat[0])

    start = sum(val << (i*n + j) for i, row in enumerate(mat) for j, val in enumerate(row))

    queue = collections.deque([(start, 0)])
    seen = { start }

    dirs = [[0, 0], [0,1], [1, 0], [0, -1], [-1, 0]]
    while queue:
        # print(queue)
        current, d = queue.popleft()
        if current == 0:
            return d

        # for each index in matrix find neighbour
        for i in range(len(mat)):
            for j in range(len(mat[0])):
                next_state = current

                # importants dirs has [0, 0] we need flip the current element and neigbour
                for dir_ in dirs:
                    new_i = i + dir_[0]
                    new_j = j + dir_[1]

                    if new_i >= 0 and new_i < len(mat) and new_j >= 0 and new_j < len(mat[0]):
                        next_state ^= (1 << (new_i * n + new_j )) # 0 xor 1 = 1, 1 xor 1 = 0

                if next_state not in seen:
                    seen.add(next_state)
                    queue.append((next_state, d + 1))

    return -1

def shortestSuperstring( A: list[str]) -> str:
    A = [a for i, a in enumerate(A) if all(a not in b for j, b in enumerate(A) if i != j)]

    def memo(f):
        dic = {}

        def f_alt(*args):
            if args not in dic:
                dic[args] = f(*args)
            return dic[args]
        return f_alt

    def merge(w1, w2):
        for k in range(len(w2), -1, -1):
            if w1.endswith(w2[:k]):
                return w1+w2[k:]

    @memo
    def find_short(tup, last):
        if len(tup) == 1:
            return A[tup[0]]
        mtup = tuple(t for t in tup if t != last)
        return min((merge(find_short(mtup, t), A[last]) for t in mtup), key=len)

    tup = tuple(range(len(A)))

    return min((find_short(tup, i) for i in range(len(A))), key=len)

def minScoreTriangulation( A: list[int]) -> int:
    N = len(A)
    dp = [[0]*N for _ in range(N)]

    for i in range(N-2, -1, -1):
        for j in range(i+2, N):
            dp[i][j] = min(dp[i][k]+dp[k][j]+A[i]*A[j]*A[k] for k in range(i+1, j))

    return dp[0][-1]

def minMalwareSpread( graph: list[list[int]], initial: list[int]) -> int:
    from collections import deque


    def bfs(graph, seed, removed):
        queue = deque(seed)
        visited = seed

        while len(queue) > 0:
            node = queue.popleft()
            for next_node in range(len(graph[node])):
                if graph[node][next_node] == 0 or next_node in visited or next_node == removed:
                    continue
                visited.add(next_node)
                queue.append(next_node)
        return len(visited)

    best = len(graph)
    best_remove = initial[0]
    initial = set(initial)

    for remove_node in initial:
        initial_removed = initial - {remove_node}
        node_result = bfs(graph, initial_removed, remove_node)

        if (node_result < best) or (node_result == best) and (best_remove > remove_node):
            best = node_result
            best_remove = remove_node
    return best_remove

def kthFactor( n: int, k: int) -> int:
    i = 0
    for j in range(1, n+1):
        if n % j == 0:
            i += 1
            if i == k:
                return j
    return -1

def rankTeams( votes: list[str]) -> str:
    '''
    ABC
    ACB
    X 1 2 3
    A 2 0 0
    B 0 1 1
    C 0 1 1
    '''

    mem = {}
    for vote in votes:
        for i in range(len(vote)):
            team = vote[i]
            if team not in mem:
                mem[team] = [0 for _ in range(len(vote))]
            mem[team][i] += 1

    standings = []
    for k, v in mem.items():
        standings.append(tuple(v) + (-ord(k), k))

    standings.sort(reverse=True)

    res = [s[-1] for s in standings]
    return ''.join(res)

def splitArraySameAverage( A: list[int]) -> bool:
    N, S = len(A), sum(A)
    if N == 1: return False
    A = [z * N - S for z in A] 
    mid, left, right = N//2, {A[0]}, {A[-1]}


    if not any((S*size) % N == 0 for size in range(1, mid+1)): return False

    for i in range(1, mid): left |= {z + A[i] for z in left} | {A[i]}
    for i in range(mid, N-1): right |= {z + A[i] for z in right} | {A[i]}
    if 0 in (left|right): return True


    left -= {sum(A[:mid])}
    return any(-ha in right for ha in left)

def winnerSquareGame( n: int) -> bool:
    import math

    dp: list[int] = [0] * (n+1)
    candidates: list[int] = []
    for j in range(1, int(math.sqrt(n))+1):
        candidates.append(j*j)
    for i in range(n):
        if not dp[i]:
            for can in candidates:
                if i + can < n:
                    dp[i+can] = 1
                elif i + can == n:
                    return 1
    return dp[-1]

def oddEvenJumps( A: list[int]) -> int:
    def findNextHighestIdx(B: list[int]) -> list[int]:
        next_idx_list = [None] * len(B)
        stack = []
        for i in B:
            while stack and stack[-1] < i:
                next_idx_list[stack.pop()] = i
            stack.append(i)
        return next_idx_list

    N = len(A)
    B = sorted(range(N), key=lambda i: A[i])
    oddnextidx = findNextHighestIdx(B)
    B.sort(key=lambda i: -A[i])
    evennextidx = findNextHighestIdx(B)

    odd = [False] * N
    odd[N-1] = True
    even = [False] * N
    even[N-1] = True

    for i in range(N-2, -1, -1):
        if oddnextidx[i] is not None:
            odd[i] = even[oddnextidx[i]]
        if evennextidx[i] is not None:
            even[i] = odd[evennextidx[i]]

    return sum(odd)

def smallestRepunitDivByK( K: int) -> int:
    if K % 2 == 0 or K % 5 == 0: return -1
    r = 0
    for N in range(1, K + 1):
        r = (r * 10 + 1) % K
        if not r: return N

def findBestValue( arr: list[int], target: int) -> int:
    arr.sort()
    n = len(arr)
    for i in range(n):
        sol = round(target / n)
        if arr[i] >= sol:
            return sol
        target -= arr[i]
        n -= 1
    return arr[-1]

def kConcatenationMaxSum( arr: list[int], k: int) -> int:
    oneArrSum = sum(arr)
    twoArr = arr + arr

    def findMaxSub(array):
        if len(array) == 1:
            return array[0]

        cur = 0
        small = 0
        ret = -999999
        for i in array:
            cur += i
            small = cur if cur < small else small
            ret = cur - small if cur - small > ret else ret

        return 0 if ret < 0 else ret

    if not arr:
        return 0
    if k == 1:
        return findMaxSub(arr)

    ret = findMaxSub(twoArr)
    if oneArrSum > 0 and k > 2:
        ret += (k-2)*oneArrSum
    return ret % (10**9 + 7)

def breakPalindrome( palindrome: str) -> str:
    if len(palindrome) == 1:
        return ''
    for i, val in enumerate(palindrome):
        if val != 'a' and i != len(palindrome) // 2:
            return palindrome[:i] + 'a' + palindrome[i+1:]
        elif val == 'a' and i == len(palindrome) - 1:
            return palindrome[:-1] + 'b'

def minSwap( A: list[int], B: list[int]) -> int:

    n = len(A)

    if n == 1:
        return 0

    dp = [[float('inf'), float('inf')] for _ in range(n)]
    dp[0] = [0,1] #[natural, swapped]

    for i in range(1, n):
        if A[i-1] < A[i] and B[i-1] < B[i]:
            dp[i] = [dp[i-1][0], dp[i-1][1]+1]
        if A[i-1] < B[i] and B[i-1] < A[i]:
            dp[i] = [min(dp[i][0],dp[i-1][1]), min(dp[i][1],dp[i-1][0]+1)]

    print(dp)


    return min(dp[-1])

def catMouseGame( graph: list[list[int]]) -> int:
    N = len(graph)

    # What nodes could play their turn to
    # arrive at node (mouse, cat, turn) ?
    def parents(mouse, cat, turn):
        prev_turn = 3 - turn
        if prev_turn == MOUSE: 
            for m2 in graph[mouse]:
                yield m2, cat, prev_turn
        else:
            for c2 in graph[cat]:
                if c2:
                    yield mouse, c2, prev_turn

    DRAW, MOUSE, CAT = 0, 1, 2
    colors = collections.defaultdict(int)

    # degree[node] : the number of neutral children of this node
    degree = {}
    for mouse in range(N):
        for cat in range(N):
            degree[mouse, cat, MOUSE] = len(graph[mouse])
            degree[mouse, cat, CAT] = len(graph[cat]) - (0 in graph[cat])  # cat can not be at hole 0

    # enqueued : all nodes that are colored
    queue = collections.deque([])
    for cat in range(N):
        for turn in [MOUSE, CAT]:
            # color MOUSE for all node with mouse=0
            mouse = 0
            colors[mouse, cat, turn] = MOUSE
            queue.append((mouse, cat, turn, MOUSE))
            # color CAT for all node with mouse = cat !=0, cat can not be at hole 0
            if cat > 0:
                mouse = cat
                colors[mouse, cat, turn] = CAT
                queue.append((mouse, cat, turn, CAT))

    # percolate
    while queue:
        mouse, cat, turn, color = queue.popleft()
        for prev_mouse, prev_cat, prev_turn in parents(mouse, cat, turn):
            # if this parent is not colored :
            if colors[prev_mouse, prev_cat, prev_turn] is DRAW:
                # if the parent can make a winning move (ie. mouse to MOUSE), do so
                if prev_turn == color: # winning move
                    colors[prev_mouse, prev_cat, prev_turn] = color
                    queue.append((prev_mouse, prev_cat, prev_turn, color))
                    if prev_mouse == 1 and prev_cat == 2 and prev_turn == MOUSE: 
                        return color
                # else, this parent has degree[parent]--, and enqueue if all children
                # of this parent are colored as losing moves
                else:
                    degree[prev_mouse, prev_cat, prev_turn] -= 1
                    if degree[prev_mouse, prev_cat, prev_turn] == 0:
                        colors[prev_mouse, prev_cat, prev_turn] = 3 - prev_turn
                        queue.append((prev_mouse, prev_cat, prev_turn, 3 - prev_turn))
                        if prev_mouse == 1 and prev_cat == 2 and prev_turn == MOUSE: 
                            return color

    return colors[1, 2, 1] # mouse at 1, cat at 2, MOUSE turn

def findTheLongestSubstring( s: str) -> int:
    s = s + 'a'
    bits, dp = {'a':0,'e':1,'i':2,'o':3,'u':4}, {0:-1}
    res = 0
    key = 0
    for i, char in enumerate(s):                
        if char in bits:
            if key in dp:
                res = max(res, i-dp[key] - 1)
            key = key ^ (1 << bits[char])
            if key not in dp:
                dp[key] = i
    return res

def lastSubstring( s: str) -> str:
    #mx = \"\"
    #for i in range(len(s)):
    #    mx = max(mx,s[i:])
    #return mx
    index = {c: i for i, c in enumerate(sorted(set(s)))}
    cur, radix, max_val, max_i = 0, len(index), 0, 0
    for i in range(len(s)-1, -1, -1):
        cur = index[s[i]] + cur/radix
        if cur > max_val:
            max_val, max_i = cur, i
    return s[max_i:]

def longestSubsequence( arr: list[int], difference: int) -> int:
    from collections import defaultdict

    count_dict = defaultdict(int)
    for num in arr:
        count_dict[num] = count_dict[num-difference] + 1
    return max(count_dict.values())

def sumSubarrayMins( A: list[int]) -> int:
    stack = []
    result = 0
    A = [0] + A + [0]

    for i, x in enumerate(A):
        while stack and x < A[stack[-1]]:
            j = stack.pop()
            result += A[j] * (i - j) * (j - stack[-1])
        stack.append(i)

    return result % (10**9 + 7)

def numOfSubarrays( arr: list[int], k: int, threshold: int) -> int:
    if len(arr) < k:
        return 0
    bar = k * threshold
    total = 0
    window = sum(arr[:k])
    if window >= bar:
        total += 1
    for i in range(k, len(arr)):
        window -= arr[i - k]
        window += arr[i]
        if window >= bar:
            total += 1
    return total

def longestSubarray( nums: list[int]) -> int:
    if not 0 in nums:
        return len(nums) - 1
    ans = 0
    tot = 0
    prev = 0

    for n in nums:
        if n == 1:
            tot += 1
        else:
            ans = max(tot+prev, ans)
            prev = tot
            tot = 0
    return max(prev+tot, ans)

def decodeAtIndex( S: str, K: int) -> str:
    size = 0
    # Find size = length of decoded string
    for c in S:
        if c.isdigit():
            size *= int(c)
        else:
            size += 1
    for c in reversed(S):
        K %= size
        if K == 0 and c.isalpha():
            return c

        if c.isdigit():
            size /= int(c)
        else:
            size -= 1

def findLatestStep( arr: list[int], m: int) -> int:
    A = arr
    if m == len(A): 
        return m
    length = [0] * (len(A) + 2)
    res = -1
    for i, a in enumerate(A):
        left, right = length[a - 1], length[a + 1]
        if left == m or right == m:
            res = i
        length[a - left] = length[a + right] = left + right + 1
    return res

def mirrorReflection( p: int, q: int) -> int:
    while p % 2 == 0 and q % 2 == 0:
        p = p // 2
        q = q // 2
    if p % 2 == 1 and q % 2 == 0:
        return 0
    elif p % 2 == 1 and q % 2 == 1:
        return 1
    else :
        return 2

def minDifference( nums: list[int]) -> int:
    if len(nums) <= 4:
        return 0
    else:
        # nums = sorted(nums)
        nums.sort()
        threeZero = nums[-1] - nums[3]
        twoOne = nums[-2] - nums[2]
        oneTwo = nums[-3] - nums[1]
        zeroThree = nums[-4] - nums[0]
        return min(threeZero,twoOne,oneTwo,zeroThree)

def isRationalEqual( S: str, T: str) -> bool:
    import math
    if len(S) == 0 or len(T) == 0:
        return False
    def process(s):
        if s[-1] == '.':
            s = s[:-1]
        stack, repeat_9 = [], False
        for i, x in enumerate(s):
            if x != ')':
                stack.append(x)
            else:
                tmp = ''
                while stack[-1] != '(':
                    tmp += stack.pop()
                if len(tmp) == tmp.count('9'):
                    repeat_9 = True
                stack.pop()
                return ''.join(stack) + tmp[::-1] * (24 // len(tmp)), repeat_9
        return ''.join(stack), repeat_9

    x, y = process(S), process(T)
    if x[0].count('.') == 0 or y[0].count('.') == 0:
        return float(x[0]) == float(y[0])
    l = max(len(x[0]), len(y[0]))
    if x[0][:17] == y[0][:17]:
        return True
    if x[1] or y[1]:
        m = min(len(x[0].split('.')[1]), len(y[0].split('.')[1]))
        if round(float(x[0]), m) == round(float(y[0]), m):
            return True

    return False

def minDifficulty( jobDifficulty: list[int], d: int) -> int:
    N = len(jobDifficulty)
    if N < d: 
        return -1

    dp = [jobDifficulty[0]]
    for j in jobDifficulty[1:]:
        dp.append(max(dp[-1], j))

    for i in range(1, d):

        dp_curr = [0] * N

        stack = []
        for j in range(i, N):
            dp_curr[j] = dp[j - 1] + jobDifficulty[j]

            while stack and jobDifficulty[stack[-1]] <= jobDifficulty[j]:
                dp_curr[j] = min(dp_curr[j], dp_curr[stack[-1]] - jobDifficulty[stack[-1]] + jobDifficulty[j])
                stack.pop()

            if stack:
                dp_curr[j] = min(dp_curr[j], dp_curr[stack[-1]]) 
            stack.append(j)

        dp = dp_curr
    return dp[-1]

def isPrintable( targetGrid: list[list[int]]) -> bool:
    from collections import deque

    grids = targetGrid
    num_to_range = dict()
    for i, row in enumerate(targetGrid):
        for j, val in enumerate(row):
            if val not in num_to_range:
                # up, down, left, right
                num_to_range[val] = [i, i, j, j]
            num_to_range[val][0] = min(num_to_range[val][0], i)
            num_to_range[val][1] = max(num_to_range[val][1], i)
            num_to_range[val][2] = min(num_to_range[val][2], j)
            num_to_range[val][3] = max(num_to_range[val][3], j)
    #print(num_to_range)

    m = len(grids)
    n = len(grids[0])
    grid_list = [[list() for j in range(n)] for i in range(m)]
    for num, val in list(num_to_range.items()):
        for i in range(val[0], val[1]+1):
            for j in range(val[2], val[3]+1):
                grid_list[i][j].append(num)

    paths = {val: set() for val in list(num_to_range)}
    for i, row in enumerate(targetGrid):
        for j, val in enumerate(row):
            for parent in grid_list[i][j]:
                if parent != val:
                    paths[parent].add(val)

    parent_counter = {val: 0 for val in list(num_to_range)}
    for parent, childs in list(paths.items()):
        for child in childs:
            parent_counter[child] += 1

    queue = deque()
    for child, cnt in list(parent_counter.items()):
        if cnt == 0:
            queue.append(child)

    seen = set()
    while queue:
        parent = queue.popleft()
        seen.add(parent)
        for child in paths[parent]:
            parent_counter[child] -= 1
            if parent_counter[child] == 0:
                queue.append(child)



    return len(seen) == len(num_to_range)

def coinChange( coins: list[int], amount: int) -> int:
    coins.sort(reverse=True)
    n, res = len(coins), amount + 1

    def dfs(index, target, cnt):
        nonlocal res
        if cnt + (target + coins[index] - 1) // coins[index] >= res:
            return

        if target % coins[index] == 0:
            res = cnt + target // coins[index]
            return

        if index == n - 1:
            return

        for i in range(target // coins[index], -1, -1):
            dfs(index + 1, target - coins[index] * i, cnt + i)

    dfs(0, amount, 0)
    return -1 if res > amount else res

def minSubarray( nums: list[int], p: int) -> int:
    need = sum(nums) % p
    if need == 0:
        return 0
    pos = {0: -1}
    total = 0
    ans = float('inf')
    for i, num in enumerate(nums):
        total = (total + num) % p
        target = (total - need) % p
        if target in pos:
            ans = min(ans, i - pos[target])
        pos[total] = i
    return ans if ans < len(nums) else -1

def numOfMinutes( n: int, headID: int, manager: list[int], informTime: list[int]) -> int:
    def dfs(i):
        if manager[i] != -1:
            informTime[i] += dfs(manager[i])
            manager[i] = -1
        return informTime[i]
    return max(list(map(dfs, manager)))

def countServers( grid: list[list[int]]) -> int:
    #[Runtime: 452 ms, faster than 97.27%] Hash
    #O(MN)
    #1. traverse all cells and mark server as (x, y)
    #2. put each server (x, y) into serveral bucket named x1, x2, .., and y1, y2, ..
    # e.g. each xbucket[x1] maintains the number of servers on line x1
    #3. enumerate all server (x', y'), and see if there is at least 2 server on xbucket[x'] or ybucket[y'] 
    xbucket, ybucket, server = [0] * len(grid), [0] * len(grid[0]), []
    for x, row in enumerate(grid):
        for y, cell in enumerate(row):
            if cell:
                server.append((x, y))
                xbucket[x] += 1
                ybucket[y] += 1
    return sum(xbucket[x] > 1 or ybucket[y] > 1 for x, y in server)

def maskPII( S: str) -> str:
    if '@' in S:
        name, domain = S.split('@')
        return name[0].lower() + '*****' + name[-1].lower() + '@' + domain.lower()
    else:
        number = ''
        for c in S:
            if c.isdigit():
                number += c
        if len(number) == 10:
            return '***-***-' + number[-4:]
        else:
            return '+' + '*'*(len(number)-10) + '-***-***-' + number[-4:]

def sumFourDivisors( nums: list[int]) -> int:
    # 1390. Four Divisors
    # version 2, with optimized prime-finding.

    import math

    def remove (lst, index):
        assert lst
        tail = len (lst) - 1
        lst[index], lst[tail] = lst[tail], lst[index]
        lst.pop ()

    def swap_min (lst):
        if not lst: return
        argmin = min (range (len (lst)), key = lambda i: lst[i])
        lst[0], lst[argmin] = lst[argmin], lst[0]

    def find_primes (top):
        candidates = list (range (2, top))
        primes = []
        while candidates:
            # here, candidates[0] is the least element.
            latest_prime = candidates[0]
            primes.append (latest_prime)
            remove (candidates, 0)
            for i in range (len (candidates) - 1, -1, -1):
                if candidates[i] % latest_prime == 0:
                    remove (candidates, i)

            swap_min (candidates)
            # before continuing, set candidates[0] to be the least element.
        return primes

    def find_prime_factor (n, primes):
        for p in primes:
            if n % p == 0:
                return p

    def div4 (n, primes, setprimes):
        if n <= 3:
            return 0
        elif n in setprimes:
            return 0
        else:
            p1 = find_prime_factor (n, primes)
            if p1 is None:
                return 0
            p2 = find_prime_factor (n // p1, primes)
            if p2 is None:
                p2 = n // p1
            if p1 * p2 == n and p1 != p2:
                # success
                return (1 + p1) * (1 + p2)
            elif p1 ** 3 == n:
                # success
                return (1 + p1) * (1 + p1**2)
            else:
                return 0

    def sum_four_divisors (arr):
        top = math.ceil (math.sqrt (max (arr) + 5))
        primes = find_primes (top)
        setprimes = set (primes)
        return sum (div4 (elem, primes, setprimes) for elem in arr)

    return sum_four_divisors(nums)

def canReach( arr: list[int], start: int) -> bool:

    dq = collections.deque([start])
    visited = set([start])

    while dq:

        curr = dq.pop()

        if arr[curr] == 0:
            return True

        if (curr + arr[curr]) not in visited and (curr + arr[curr]) < len(arr):
            dq.appendleft(curr + arr[curr])
            visited.add(curr + arr[curr])
        if (curr - arr[curr]) not in visited and (curr - arr[curr]) >= 0:
            dq.appendleft(curr - arr[curr])
            visited.add(curr - arr[curr])

    return False

def rangeSum( nums: list[int], n: int, left: int, right: int) -> int:
    # B: partial sum of A
    # C: partial sum of B
    # Use prefix sum to precompute B and C
    A = nums
    B, C = [0] * (n + 1), [0] * (n + 1)
    for i in range(n):
        B[i + 1] = B[i] + A[i]
        C[i + 1] = C[i] + B[i + 1]

    # Use two pointer to
    # calculate the total number of cases if B[j] - B[i] <= score
    def count_sum_under(score):
        res = i = 0
        for j in range(n + 1):
            while B[j] - B[i] > score:
                i += 1
            res += j - i
        return res

    # calculate the sum for all numbers whose indices are <= index k
    def sum_k_sums(k):
        score = kth_score(k)
        res = i = 0
        for j in range(n + 1):
            # Proceed until B[i] and B[j] are within score
            while B[j] - B[i] > score:
                i += 1
            res += B[j] * (j - i + 1) - (C[j] - (C[i - 1] if i else 0))
        return res - (count_sum_under(score) - k) * score

    # use bisearch to find how many numbers ae below k
    def kth_score(k):
        l, r = 0, B[n]
        while l < r:
            m = (l + r) // 2
            if count_sum_under(m) < k:
                l = m + 1
            else:
                r = m
        return l

    # result between left and right can be converted to [0, right] - [0, left-1] (result below right - result below left-1)
    return (sum_k_sums(right) - sum_k_sums(left - 1))%(10**9 + 7)

def carFleet( target: int, position: list[int], speed: list[int]) -> int:
    if not position:
        return 0

    posToSpeed = {position[i]: speed[i] for i in range(len(position))}
    position.sort()

    leaderTime = (target - position[-1]) / posToSpeed[position[-1]]
    currGroups = 1
    for i in range(len(position) - 2, -1, -1):
        currTime = (target - position[i]) / posToSpeed[position[i]]
        if currTime > leaderTime:
            currGroups += 1
            leaderTime = currTime

    return currGroups

def findKthBit( n: int, k: int) -> str:
    i = n - 1
    invert = False
    while i > 0:
        half_len = (2**(i + 1) - 1) // 2 
        if k == half_len + 1:
            return '1' if not invert else '0'

        if k > half_len:
            k = half_len - (k - half_len - 1) + 1
            invert = not invert
        i -= 1

    return '1' if invert else '0'

def numWays( steps: int, arrLen: int) -> int:
    # https://leetcode.com/problems/number-of-ways-to-stay-in-the-same-place-after-some-steps/discuss/569521/7-python-approaches-with-Time-and-Space-analysis
    r = min(arrLen, steps // 2 + 1)
    dp = [0, 1]
    for t in range(steps):
        dp[1:] = [sum(dp[i-1:i+2]) for i in range(1, min(r+1, t+3))]
    return dp[1] % (10**9+7)

def queryString( S: str, N: int) -> bool:
    for i in range(1,N+1):
        b = bin(i).replace('0b','')
        if b not in S:
           return False
    return True

def longestDiverseString( a: int, b: int, c: int) -> str:
    if a == 0 and b == 0 and c == 0:
        return ''

    res = ''

    heap = [(-a, 'a'), (-b, 'b'), (-c, 'c')]
    heapq.heapify(heap)
    prev_val = 0
    prev_char = ''

    while heap:
        v, char = heapq.heappop(heap)
        if prev_val < 0:
            heapq.heappush(heap, (prev_val, prev_char))

        if abs(v) >= 2:
            if abs(v) > abs(prev_val):
                res += char*2
                v += 2
            else:
                res += char
                v += 1
        elif abs(v) == 1:
            res += char
            v +=1
        elif abs(v) == 0:
            break

        prev_val = v
        prev_char = char

    return res

def maxWidthRamp( A: list[int]) -> int:
    width = 0
    icandidate = [0]
    for i in range(len(A)):
        if A[i] < A[icandidate[-1]]:
            icandidate.append(i)
    for j in range(len(A) - 1, -1, -1):
        while icandidate and A[icandidate[-1]] <= A[j]:
            width = max(width, j - icandidate.pop())
    return width

def canVisitAllRooms( rooms: list[list[int]]) -> bool:
    def dfs(node, visited):
        if node in visited:
            return
        visited.add(node)
        for nei in rooms[node]:
            if nei in visited:
                continue
            dfs(nei,visited)
        return
    visited = set()
    dfs(0, visited)
    if len(visited) == len(rooms):
        return True
    else: 
        return False

def strWithout3a3b( A: int, B: int) -> str:
    if A >= 2*B:
        return 'aab'* B + 'a'* (A-2*B)
    elif A >= B:
        return 'aab' * (A-B) + 'ab' * (2*B - A)
    elif B >= 2*A:
        return 'bba' * A + 'b' *(B-2*A)
    else:
        return 'bba' * (B-A) + 'ab' * (2*A - B)

def minIncrementForUnique( A: List[int]) -> int:
    if not A:
        return 0

    A.sort()
    prev = A[0]
    res = 0
    for num in A[1:]:
        if num <= prev:
            prev += 1
            res += prev-num

        else:
            prev = num

    return res

def jobScheduling( startTime: List[int], endTime: List[int], profit: List[int]) -> int:

    # max profit ending at time t
    dp = [(0,0)]

    task = [(startTime[i], endTime[i], profit[i]) for i in range(len(startTime))]
    task = sorted(task, key = lambda x: x[1])

    for s, e, p in task:
        noTaskProf = dp[-1][1]
        for end, pro in reversed(dp):
            # end, pro = dp[i]
            if end <= s:
                doTaskProf = pro + p
                break
        if doTaskProf > noTaskProf:
            dp.append((e, doTaskProf))
    return dp[-1][1]

def minNumberOperations( target: List[int]) -> int:
    prev = -1
    ans = 0
    for num in target:
        if prev == -1:
            prev = num
            ans += num
            continue
        if num > prev:
            ans += (num - prev)
        #print(ans, num, prev)
        prev = num
    return ans

def minMalwareSpread( graph: List[List[int]], initial: List[int]) -> int:
    # 1. Color each component.
    # colors[node] = the color of this node.

    N = len(graph)
    colors = {}
    c = 0

    def dfs(node, color):
        colors[node] = color
        for nei, adj in enumerate(graph[node]):
            if adj and nei not in colors:
                dfs(nei, color)

    for node in range(N):
        if node not in colors:
            dfs(node, c)
            c += 1

    # 2. Size of each color.
    # size[color] = number of occurrences of this color.
    size = collections.Counter(colors.values())

    # 3. Find unique colors.
    color_count = collections.Counter()
    for node in initial:
        color_count[colors[node]] += 1

    # 4. Answer
    ans = float('inf')
    for x in initial:
        c = colors[x]
        if color_count[c] == 1:
            if ans == float('inf'):
                ans = x
            elif size[c] > size[colors[ans]]:
                ans = x
            elif size[c] == size[colors[ans]] and x < ans:
                ans = x

    return ans if ans < float('inf') else min(initial)

def arrangeWords( text: str) -> str:
    p=text.split(' ')
    final=''
    j=sorted(p,key=len)
    temp=' '.join(j)
    if temp[0]>='a' and temp[0]<='z':
        s=temp[0].swapcase()
        final=final+s[0]
    else:
        final=final+temp[0]
    for i in range(1,len(temp)):
        if temp[i]>='A' and temp[i]<='Z':
            s=temp[i].swapcase()
            final=final+s[0]
        else:
            final=final+temp[i]
    return final

def reverseParentheses( s: str) -> str:


    stack = []
    curr = ''
    for c in s:
        if c=='(':
            stack.append(curr)
            curr = ''
            stack.append('(')
        elif c==')':
            stack.append(curr)
            curr = ''
            aux = ''
            while stack and stack[-1]!='(':
                aux=stack.pop()+aux
            stack.pop()
            stack.append(aux[::-1])
        else:
            curr+=c
    if curr:
        stack.append(curr)
    return ''.join(stack)

def minRemoveToMakeValid( s: str) -> str:
    if not s: return s
    l=0
    r=0
    res=''
    for i,c in enumerate(s):
        if c=='(':
            l+=1
        if c==')':
            if l==r:
                continue
            else:
                r+=1
        res+=c
    s=res
    l=0
    r=0
    res=''
    for i in range(len(s)-1,-1,-1):
        c=s[i]
        if c==')':
            r+=1
        if c=='(':
            if l==r:
                continue
            else:
                l+=1
        res=c+res
    return res

def sum_of_intervals(intervals):
    s, top = 0, float("-inf")
    for a,b in sorted(intervals):
        if top < a: top    = a
        if top < b: s, top = s+b-top, b
    return s

def find_spec_prod_part(n, com):
    def primeFactors(n):

        factors = []

        while n % 2 == 0: 
            n /= 2
            factors.append(2)

        for i in range(3, int(n**.5) + 1,2): 
            while n % i == 0: 
                n /= i
                factors.insert(0, i)

        if n > 2: factors.insert(0, int(n))

        return factors

    def score(p):

        last, xp, s = p[0], p[0], 0

        for j in p[1:]:
            if j == last:
                xp *= j
            else:
                s += xp
                xp, last = j, j
        return (s + xp) * len(p)


    def prod(lst):

        res = 1

        for v in lst: res *= v
        return res

    def multiply_partitions(partition): return [prod(sub) for sub in partition]

    def partition(collection):

        if len(collection) == 1:
            yield [collection]
            return

        first = collection[0]

        for smaller in partition(collection[1:]):      
            for n, subset in enumerate(smaller):
                yield smaller[:n] + [[ first ] + subset]  + smaller[n+1:]
            yield [ [ first ] ] + smaller



    factors = primeFactors(n)

    if len(factors) == 1: return 'It is a prime number'

    fn = min if com == 'min' else max
    mplist = []
    best = [factors, score(factors)]

    for p in partition(factors):
        mp = multiply_partitions(p)

        if mp in mplist or mp[0]==n:
            continue            
        mplist.append(mp)
        best = fn(best, [mp, score(mp)], key=lambda x: x[1])

    return [sorted(best[0], reverse=True), best[1]]

def count_change(money, coins):
    if money<0:
        return 0
    if money == 0:
        return 1
    if money>0 and not coins:
        return 0
    return count_change(money-coins[-1],coins) + count_change(money,coins[:-1])

def bowling_score(frames):
    rolls = list(frames.replace(' ',''))
    for i, hit in enumerate(rolls):
        if hit == 'X':
            rolls[i] = 10
        elif hit == '/':
            rolls[i] = 10 - rolls[i - 1]
        else:
            rolls[i] = int(hit)
    score = 0
    for i in range(10):
        frame = rolls.pop(0)
        if frame == 10:
            score += frame + rolls[0] + rolls[1]    # Strike!
        else:
            frame += rolls.pop(0)
            score += frame
            if frame == 10:
                score += rolls[0]                   # Spare!
    return score
